+    fn bundle_tls_bidirectional_exchange() {
+        run_async_test(async {
+            let ca_cert = temp_pem(CA_CERT);
+            let server_cert = temp_pem(SERVER_CERT);
+            let server_key = temp_pem(SERVER_KEY);
